import React from 'react';
import { VietQR, VietQRProps } from '@viet-qr/react';
import { getBankByBin, getBankByShortName } from '@viet-qr/core';

export interface PayStandeeProps extends VietQRProps {
  title?: string;
  subtitle?: string;
  theme?: 'light' | 'dark';
}

export const PayStandee: React.FC<PayStandeeProps> = ({ 
  title = "Quét mã để thanh toán", 
  subtitle = "Hỗ trợ ứng dụng ngân hàng & ví điện tử", 
  theme = 'light',
  ...qrProps 
}) => {
  const bankInfo = React.useMemo(() => {
    return getBankByBin(qrProps.bankId) || getBankByShortName(qrProps.bankId);
  }, [qrProps.bankId]);

  const bankName = bankInfo?.shortName || qrProps.bankId;

  return (
    <div className={`vqr-pay-standee vqr-theme-${theme}`}>
      <div className="vqr-pay-standee__banner">
        <h2 className="vqr-pay-standee__title">{title}</h2>
        <p className="vqr-pay-standee__subtitle">{subtitle}</p>
      </div>

      <div className="vqr-pay-standee__body">
        <div className="vqr-pay-standee__qr-wrapper">
          <VietQR {...qrProps} size={qrProps.size || 200} />
        </div>

        <div className="vqr-pay-standee__info">
          {qrProps.accountName && <h3 className="vqr-pay-standee__name">{qrProps.accountName}</h3>}
          <p className="vqr-pay-standee__account">{qrProps.accountNo}</p>
          <p className="vqr-pay-standee__bank">Ngân hàng {bankName}</p>
        </div>
      </div>
    </div>
  );
};
