import React from 'react';
import { VietQR, VietQRProps } from '@viet-qr/react';
import { getBankByBin, getBankByShortName } from '@viet-qr/core';

export interface CompactCardProps extends VietQRProps {
  bankLogo?: string;
  theme?: 'light' | 'dark';
}

export const CompactCard: React.FC<CompactCardProps> = ({ bankLogo, theme = 'light', ...qrProps }) => {
  // Attempt to auto-resolve bank name if not provided
  const bankInfo = React.useMemo(() => {
    return getBankByBin(qrProps.bankId) || getBankByShortName(qrProps.bankId);
  }, [qrProps.bankId]);

  const bankName = bankInfo?.shortName || qrProps.bankId;
  const formattedAmount = qrProps.amount ? new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(qrProps.amount) : null;

  return (
    <div className={`vqr-compact-card vqr-theme-${theme}`}>
      <div className="vqr-compact-card__header">
        {bankLogo && <img src={bankLogo} alt={bankName} className="vqr-compact-card__logo" />}
        {!bankLogo && <h3 className="vqr-compact-card__bank-name">{bankName}</h3>}
      </div>

      <div className="vqr-compact-card__qr-wrapper">
        <VietQR {...qrProps} />
      </div>

      <div className="vqr-compact-card__info">
        {qrProps.accountName && (
          <div className="vqr-compact-card__info-row">
            <span className="vqr-compact-card__label">Tên tài khoản</span>
            <p className="vqr-compact-card__value">{qrProps.accountName}</p>
          </div>
        )}
        
        <div className="vqr-compact-card__info-row">
          <span className="vqr-compact-card__label">Số tài khoản</span>
          <p className="vqr-compact-card__value">{qrProps.accountNo}</p>
        </div>

        {formattedAmount && (
          <div className="vqr-compact-card__info-row" style={{ marginTop: '16px' }}>
            <span className="vqr-compact-card__label">Thanh toán</span>
            <p className="vqr-compact-card__amount">{formattedAmount}</p>
          </div>
        )}
      </div>
    </div>
  );
};
